query ActivityLogQuery(
  $zoneTag: string
  $filter: HealthCheckEventsAdaptiveGroupsFilter_InputObject
  $activityFilter: HealthCheckEventsAdaptiveFilter_InputObject
  $limit: int64!
) {
  viewer {
    zones(filter: { zoneTag: $zoneTag }) {
      total: healthCheckEventsAdaptiveGroups(limit: 1, filter: $filter)
        @connection(key: "hcEventsTotal", filter: ["filter"]) {
        count
      }
      activity: healthCheckEventsAdaptive(
        filter: $activityFilter
        limit: $limit
        orderBy: [datetime_DESC, healthCheckId_DESC, scope_DESC]
      ) {
        sampleInterval
        datetime
        failureReason
        fqdn
        healthChanged
        healthCheckId
        healthCheckName
        healthStatus
        originIP
        originResponseStatus
        expectedResponseCodes
        region
        tcpConnMs
        tlsHandshakeMs
        timeToFirstByteMs
        rttMs
        scope
      }
    }
  }
}

query EventDistributionQuery(
  $zoneTag: string
  $filter: HealthCheckEventsAdaptiveGroupsFilter_InputObject
) {
  viewer {
    zones(filter: { zoneTag: $zoneTag }) {
      distribution: healthCheckEventsAdaptiveGroups(
        limit: 9999
        filter: $filter
        orderBy: [datetimeMinute_DESC]
      ) @connection(key: "HcEventsDistribution", filter: ["filter"]) {
        c: count
        d: dimensions {
          t: datetimeMinute
        }
      }
    }
  }
}

query getOrderedHealthchecks($zoneTag: string, $filter: object) {
  viewer {
    zones(filter: { zoneTag: $zoneTag }) {
      healthCheckEventsAdaptiveGroups(
        limit: 3000
        filter: $filter
        orderBy: [healthCheckName_ASC]
      ) {
        count
        avg {
          rttMs
        }
        dimensions {
          healthStatus
          healthCheckName
        }
      }
    }
  }
}
